#include<bits/stdc++.h>
using namespace std;
int dp[100001];
int main() {
	int n;
	cin >> n;
	memset(dp, 0x3f, sizeof(dp));
	dp[0] = 0;
	for (int i = 1; i <= n; i++) {
		for (int j = 1; j * j <= i; j++) {
			dp[i] = min(dp[i], dp[i - j * j] + 1);
		}
	}cout<<dp[n];
	return 0;
}
